diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..7efacea98b0a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,39 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp ord+select pattern: fcmp pred (select (fcmp ord X, 0.0), X, 0.0), C -> fcmp pred X, C
+      // when pred is ordered and (0.0 pred C) is false.
+      // fcmp ord+select pattern: fcmp pred (select (fcmp ord X, 0.0), X, 0.0), C -> fcmp pred X, C
+      // when pred is ordered and (0.0 pred C) is false.
+      {
+        Value *X2;
+        CmpPredicate Pred2;
+        if (FCmpInst::isOrdered(Pred) &&
+            match(LHSI, m_Select(m_FCmp(Pred2, m_Value(X2), m_AnyZeroFP()),
+                                 m_Deferred(X2), m_AnyZeroFP())) &&
+            Pred2 == FCmpInst::FCMP_ORD) {
+          // Ensure that C is not equal to 0.0 (or more generally, (0.0 pred C) is false)
+          Constant *Zero = ConstantFP::getZero(RHSC->getType());
+          if (Constant *Cmp = ConstantFoldCompareInstOperands(Pred, Zero, RHSC, DL))
+            if (Cmp->isNullValue())
+              return new FCmpInst(Pred, X2, RHSC, "", &I);
+        }
+      }
+      // fcmp uno+select pattern: fcmp pred (select (fcmp uno X, 0.0), 0.0, X), C -> fcmp pred X, C
+      // when pred is unordered and (0.0 pred C) is false.
+      {
+        Value *X2;
+        CmpPredicate Pred2;
+        if (FCmpInst::isUnordered(Pred) &&
+            match(LHSI, m_Select(m_FCmp(Pred2, m_Value(X2), m_AnyZeroFP()),
+                                 m_AnyZeroFP(), m_Deferred(X2))) &&
+            Pred2 == FCmpInst::FCMP_UNO) {
+          Constant *Zero = ConstantFP::getZero(RHSC->getType());
+          if (Constant *Cmp = ConstantFoldCompareInstOperands(Pred, Zero, RHSC, DL))
+            if (Cmp->isNullValue())
+              return new FCmpInst(Pred, X2, RHSC, "", &I);
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

